var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"……리플레이서 원격 네트워크에는 별다른 내용이 없네.","JPN":"……リプレイサーの遠隔ネットワークには大したデータが無いわ。","ENG":"Nothing special on the Replacers’ remote network.","TWN":"……克隆集團遠程訪問沒什麼特別的內容。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아저씨는 어때? 뭐 좀 건진 거 있어?","JPN":"おじさんのほうはどう？　何か収穫はあった？","ENG":"What about you, mister? Did you find something?","TWN":"大叔呢？有找到什麼嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"여기도 허탕이야. 서류들을 뒤져봤지만 리액터 비슷한 단어도 없군.","JPN":"こっちも無駄骨だったよ。\\n書類を漁ってみたが、リアクターのような単語すら出てこない。","ENG":"Nothing. I went through the documents, but not a word related to the reactor.","TWN":"我這裡也是一無所獲，文件上都沒有出現類似反應爐的字。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"제기랄, 대체 어디에 있는 거지?","JPN":"くそっ、いったいどこにあるんだ？","ENG":"Darn it, where is it?","TWN":"可惡！到底在哪裡？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이봐, 당장 급한 일이 터진 것도 아니잖아. 초조해 하지 말고 침착하게 찾아 보라고.","JPN":"おい、緊迫した状況でもないだろう、焦らずに落ち着いて探そう。","ENG":"Hey, no rush here, right? Stay cool, and go through the documents thoroughly.","TWN":"喂，又不是現在就發生什麼很緊急大事，冷靜點，再慢慢找吧！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그런 한가한 소리는 용병들이나 할 수 있겠지.","JPN":"そんな悠長なことは傭兵だから言えるんだ。","ENG":"I can’t slack off like you mercenaries.","TWN":"不愧是傭兵，才能說出這種風涼話。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"언제 어디서 문제가 발생하더라도 난 시민들을 지킬 수 있어야 해.","JPN":"いつどこで問題が起きようとも、俺は市民を守らなければならない。","ENG":"I have to protect people whenever an emergency comes up.","TWN":"無論什麼時候，在哪裡發生問題，我都必須保護市民！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"특히, 저런 괴물을 상대하려면…….","JPN":"あんな化け物相手なら、なおさら……","ENG":"Especially when a monster like her appears...","TWN":"更何況對手是那種怪物……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……죄송해요.","JPN":"……ごめんなさい。","ENG":"... I'm sorry.","TWN":"對不起……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"뭐, 기억도 없는 사람이 죄송하다고 해도 별 의미가 없겠지.","JPN":"まあ、記憶が無い人に謝られても意味なんて無いだろう。","ENG":"What’s the point of apologizing? You don’t even remember what you did.","TWN":"唉唷，一個失憶的人道歉有什麼意義。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그보다 죄송하면 뭔가 도움을 줬으면 좋겠군.","JPN":"それより、悪いと思うなら手伝ってくれ。","ENG":"If you’re sorry, help us.","TWN":"與其說對不起，不如幫點什麼忙吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이 기지에 대해서 떠오르는 게 없나?","JPN":"この基地について何か思い出したことはないか？","ENG":"Do you remember anything about this place?","TWN":"你對這裡有印象嗎？有想起什麼嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아. 그러고 보니 들어왔을 때부터 뭔가 묘한 기분이 들었어요.","JPN":"あ、そういえば、入った時から何だか妙な感じがしました。","ENG":"Oh, yes. Since I got here, it felt a bit weird.","TWN":"嗯！這麼說來，進到這裡來的時候，覺得哪裡怪怪的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"자세하게 설명하긴 어렵지만, 너무 좁다고 할까……?","JPN":"具体的には説明できませんが、前より狭いというか……？","ENG":"It’s hard to explain, but it felt... too narrow?","TWN":"說不太上來哪裡怪，好像是很窄的感覺……？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"좁다고……?","JPN":"狭い……？","ENG":"Narrow?","TWN":"很窄……？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 분명 이쪽으로 더 큰 공간이 있었던 것 같은 기분이……","JPN":"はい。たしかこっちにもっと広い空間があったような……","ENG":"Yes. I feel like there should be more space here...","TWN":"對，感覺這裡應該還有更大的空間……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"잠깐! 여기 시설도 어디에 있었지? 이리 가져와 봐!","JPN":"ちょっと待て！　ここの施設図はどこだ？　こっちに持ってきてくれ！","ENG":"Wait! Where is the map of this place? Bring it here!","TWN":"等等！這裡的設計圖在哪裡？拿來給我！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"왜 그래? 뭔가 찾은 건가?","JPN":"どうした？　何かを見つけたのか？","ENG":"What is it? Did you find something?","TWN":"為什麼？有發現什麼嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"여기, 시설도를 좀 봐.","JPN":"ここ、施設図を見てくれ。","ENG":"Look at this map.","TWN":"你看這個設計圖。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"우리가 타고 내려온 승강기 아래쪽이 비정상적으로 넓어 보이지 않나?","JPN":"俺たちが乗ってきたエレベーターの下の部分が、異様に広いと思わないか？","ENG":"The space below the elevator we took. It looks way too roomy.","TWN":"這是我們剛剛搭的電梯，不覺得電梯底下異常寬敞嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"이 아래쪽에 숨겨진 공간이 있다는 뜻이야.","JPN":"この下に隠された空間があるということだ。","ENG":"I believe there is a hidden space down there.","TWN":"就表示這底下肯定有密室！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"분명 이쯤 어디에 비밀 통로가 있을 텐데…….","JPN":"きっとこの辺に秘密の通路があるはずだが……","ENG":"A secret passage must be here somewhere...","TWN":"應該有秘密通道可以通到密室吧……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그렇지, 빙고!","JPN":"やっぱりな、ビンゴだ！","ENG":"Yes, bingo!","TWN":"Yeah！Bingo！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};